// ── Тихая регистрация в группу при старте приложения ────────────────────────
// Вызывается из _layout.tsx чтобы каждый пользователь попал в league_groups
// даже если он никогда не открывал экран клубов.
export async function registerInLeagueGroupSilently(): Promise<void> {
  if (!CLOUD_SYNC_ENABLED) return;
  try {
    const [[, nameRaw], [, xpRaw], [, leagueRaw], [, weekPtsRaw]] =
      await AsyncStorage.multiGet(['user_name', 'user_total_xp', 'league_state_v3', 'week_points_v2']);

    const name = (nameRaw ?? '').trim();
    if (!name) return;

    const leagueState = leagueRaw ? JSON.parse(leagueRaw) : null;
    const leagueId: number = leagueState?.leagueId ?? 0;
    const weekId: string   = leagueState?.weekId ?? '';
    if (!weekId) return;

    let weekPoints = 0;
    try {
      const wpData = weekPtsRaw ? JSON.parse(weekPtsRaw) : null;
      if (wpData?.weekKey === weekId.replace('-', '').replace('W', '')) {
        weekPoints = wpData.points ?? 0;
      }
    } catch {}

    await getOrCreateLeagueGroup(weekId, leagueId, name, weekPoints);
  } catch {}
}

